import { styleText } from 'node:util';
import { getStackTrace } from './stack.mjs';

/* eslint-disable no-console */
const FILE_PATH_REGEX = /.+?\((.+?)\)$/;
/**
 * Create a specific logger to throw a deprecation warning when a specific module / function is used.
 *
 * @param namespace Name of the module throwing the warning.
 * @param options Options to configure when to throw the warning.
 *
 * @example
 * const logDeprecated = createDeprecationLogger('my-module', { once: true });
 *
 * logDeprecated('This module is deprecated. Please migrate to the new one. Link to new module: https://my-new-module.com');
 */
function createDeprecationLogger(namespace, options = {}) {
    const PRODUCTION = process.env.NODE_ENV === 'production';
    const { once = true, moduleName = namespace, showStackTrace = false, directDependency = true, } = options;
    let alreadyWarned = false;
    const logDeprecated = (message, loggerOptions = {}) => {
        if (PRODUCTION ||
            (once && alreadyWarned) ||
            process.noDeprecation ||
            process.noProcessWarnings) {
            return;
        }
        const logMessage = (stack) => {
            let stackMsg = '';
            if (stack) {
                if (typeof stack === 'string') {
                    stackMsg = `Found module usage at: ${FILE_PATH_REGEX.exec(stack)?.[1] ?? stack}`;
                }
                else {
                    stackMsg = `Module usage stack:\n${stack.join('\n')}`;
                }
            }
            alreadyWarned = true;
            // Turn off stream validation for colors to work when using Nordic CLI (spawn child_process)
            // Since it's only on development, this is not a problem.
            console.warn(styleText('bgYellow', `[${namespace}] DEPRECATED`, {
                validateStream: false,
            }) +
                styleText('yellow', ` - ${message}\n${stackMsg}`, {
                    validateStream: false,
                }));
        };
        const stack = loggerOptions.customStack || getStackTrace().split('\n');
        // Remove the lines which include this module
        if (!loggerOptions.customStack) {
            stack.splice(0, 3);
        }
        let usageIndex = 0;
        for (; usageIndex < stack.length; usageIndex += 1) {
            if (!stack[usageIndex].includes(`node_modules/${moduleName}/`)) {
                break;
            }
        }
        const lineUsingDeprecatedModule = stack[usageIndex];
        if (!directDependency ||
            !lineUsingDeprecatedModule?.includes('node_modules/')) {
            logMessage(showStackTrace ||
                process.traceDeprecation ||
                process.traceProcessWarnings
                ? stack
                : lineUsingDeprecatedModule);
        }
    };
    return logDeprecated;
}

export { createDeprecationLogger };
